            <button class="btn btn-primary" @onclick="SearchShipment">
                Track
            </button>
        </div>
    </div>
</div>

@if (isSearching)
{
    <p><em>Searching...</em></p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5>Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @shipment.Origin</p>
                    <p><strong>To:</strong> @shipment.Destination</p>
                    <p><strong>Description:</strong> @shipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></p>
                    <p><strong>Shipped:</strong> @shipment.CreatedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</p>
                </div>
            </div>
            <div class="mt-3">
                <h6>Delivery Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar bg-success" style="width: @(GetProgress(shipment.Status))%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private Shipment? shipment;
    private bool isSearching;
    private bool searched;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isSearching = true;
        searched = false;
        shipment = null;
        StateHasChanged();

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        isSearching = false;
        searched = true;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private static int GetProgress(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 40,
        _ => 0
    };

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };
}
```

