You are implementing a Blazor Web App for a logistics company that tracks shipments. The project is already scaffolded at `/tmp/sv-24cfebe3536c4c4abbf0f03ea0b2fbff/ShipmentTracker/` with Interactive Auto Global mode and Individual authentication.

Project structure:
- `ShipmentTracker/` - Server project
- `ShipmentTracker.Client/` - Client/WebAssembly project

The App.razor already uses `InteractiveAuto` globally. The server Program.cs has Identity, EF Core with SQLite configured.

## Requirements
1. Dispatchers view a list of shipments with status and destination
2. Customers check their shipment status and estimated delivery
3. Every page has interactive controls
4. Staff and customers authenticate with individual accounts

## What to implement

### 1. Shared Models (in `.Client` project since interactive components need them)

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 2. Service Interface (in `.Client` project)

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus);
}
```
(Add the appropriate using for Models.)

### 3. Client-side implementation using HttpClient

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
        => await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
        => await http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
        => await http.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
        => await http.PutAsJsonAsync($"api/shipments/{id}/status", newStatus);
}
```

### 4. Server-side implementation using EF Core

Create `ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

Add a `DbSet<ShipmentEntity>` to the existing `ApplicationDbContext`. Find it in `ShipmentTracker/Data/ApplicationDbContext.cs` and add:
```csharp
public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
```

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(IServiceProvider sp) : IShipmentService
{
    private ApplicationDbContext CreateDbContext()
        => sp.GetRequiredService<IServiceScopeFactory>().CreateScope().ServiceProvider.GetRequiredService<ApplicationDbContext>();

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        using var db = CreateDbContext();
        return await db.Shipments.Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        using var db = CreateDbContext();
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        using var db = CreateDbContext();
        return await db.Shipments.Where(s => s.CustomerEmail == customerEmail).Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        using var db = CreateDbContext();
        var entity = await db.Shipments.FindAsync(id);
        if (entity is not null)
        {
            entity.Status = newStatus;
            await db.SaveChangesAsync();
        }
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description
    };
}
```

### 5. API Endpoints

In `ShipmentTracker/Program.cs`, add API endpoints BEFORE `app.Run()`. Add these after `app.MapAdditionalIdentityEndpoints();`:

```csharp
app.MapGet("/api/shipments", async (ShipmentTracker.Services.ShipmentServerService service) =>
    await service.GetAllShipmentsAsync())
    .RequireAuthorization();

app.MapGet("/api/shipments/track/{trackingNumber}", async (string trackingNumber, ShipmentTracker.Services.ShipmentServerService service) =>
{
    var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
}).RequireAuthorization();

app.MapGet("/api/shipments/customer/{customerEmail}", async (string customerEmail, ShipmentTracker.Services.ShipmentServerService service) =>
    await service.GetShipmentsByCustomerAsync(customerEmail))
    .RequireAuthorization();

app.MapPut("/api/shipments/{id}/status", async (int id, ShipmentTracker.Client.Models.ShipmentStatus newStatus, ShipmentTracker.Services.ShipmentServerService service) =>
{
    await service.UpdateShipmentStatusAsync(id, newStatus);
    return Results.NoContent();
}).RequireAuthorization();
```

Also register the services in server Program.cs (before `var app = builder.Build();`):
```csharp
builder.Services.AddScoped<ShipmentTracker.Services.ShipmentServerService>();
builder.Services.AddScoped<IShipmentService>(sp => sp.GetRequiredService<ShipmentTracker.Services.ShipmentServerService>());
```
Add `using ShipmentTracker.Client.Services;` at the top.

### 6. Client Program.cs registration

In `ShipmentTracker.Client/Program.cs`, register HttpClient and the client service:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

